function n(e){return e==null?"—":"¥"+Number(e).toFixed(2)}function r(e,t=2){return e==null?"—":Number(e).toFixed(t).replace(/\.?0+$/,"")}function i(e){return e==null?"—":(Number(e)*100).toFixed(2)+"%"}function a(e){return{active:"tag-active",completed:"tag-active",submitted:"tag-info",confirmed:"tag-active",queued:"tag-pending",running:"tag-pending",expired:"tag-expired",cancelled:"tag-expired",failed:"tag-error",rejected:"tag-error",pending:"tag-pending",medium:"tag-pending",high:"tag-error",low:"tag-active"}[e]||"tag-info"}function u(e){return{active:"生效中",completed:"已完成",submitted:"已提交",confirmed:"已确认",queued:"排队中",running:"进行中",expired:"已到期",cancelled:"已取消",failed:"失败",rejected:"已拒绝",pending:"待处理"}[e]||e||"—"}export{n as a,u as b,i as c,r as f,a as s};
